const express = require('express');
const jwt = require('jsonwebtoken'); // For generating token 
const bcrypt = require('bcryptjs');    // To hash passwords before storing in database  
require("dotenv").config();            // Importing dot env to manage environment variables.
var cors=require('cors')                // Middleware for handling CORS requests from different domains, allowing us to make cross-domain AJAX calls using technologies such as XMLHttpRequest or fetch API in modern browsers 
const mongoose = require("mongoose");   // Mongodb connection and data manipulation library.   
var app=express();                      // Initializing express application    
app.use(cors())                        // Middleware for handling CORS requests from different domains, allowing us to make cross-domain AJAX calls using technologies such as XMLHttpRequest or fetch API in modern browsers 
const UserSchema = new mongoose.Schema({   // Defining user schema with fields username and password (hashed)   
username: String ,                   
password :String});                  
UserSchema.methods.generateAuthToken=function(){// Generating token on successful login    
return jwt.sign({_id:this._id},process.env.JWT_SECRET,{expiresIn:'1d'});  // Signing the JWT with user id and secret key  
}   
UserSchema.pre('save',async function(next){// Hashing password before saving to database    
const user=this;                          // Getting reference of current User model instance     
if (user.isModified('password')){         // If the field is modified, hash it and save 
    user.password = await bcrypt.hash(user.password ,10);   }          return next();     });      
const LoginSchema=new mongoose.Schema({// Defining login schema with fields username & password     
username:String,                     // Username field in the database 
password : String});                  // Password Field In The Database   
app.post('/api/login',async (req , res)=>{   // Creating a POST API endpoint for logging user    
const {username , password} = req.body;      // Destructuring request body to get username and pass  word from the client side      
let loginUser=await LoginSchema.findOne({username});    // Finding User in database using their usernames  
if (!loginUser) return res.status(401).send('Username not found');     if (bcrypt.compareSync(password , loginUser.password)) {  // Comparing passwords with hashed one stored on the server side      
return res.json({token:`Bearer ${loginUser.generateAuthToken()} `});   } return res.status(401).send('Username or Password is incorrect');     });      app.listen("3002", () => console.log("\n Express server listening on port 3002\n"));